import * as React from 'react';
import { graphql } from 'gatsby';
import { Layout } from '../context/Layout';
import { ArticleCard } from '~src/components/Blog/Article';

const BlogPage = ({ data }) => {
  const seo = {
    title: 'مقالات',
  };
  return (
    <Layout seo={seo}>
      <section className="uk-section-muted uk-section-small">
        <div className="uk-container">
          <div className="uk-grid-medium uk-child-width-1-1" data-uk-grid>
            <div className="uk-grid-medium" data-uk-grid>
              <section className="uk-width-1-1 uk-width-expand@m">
                <div className="uk-grid-medium uk-child-width-1-1" datauk-grid>
                  {data.blog.nodes.map(article => (
                    <ArticleCard key={article.id} article={article} />
                  ))}
                </div>
              </section>
              {/* 
        <aside className="uk-width-1-4 uk-visible@m tm-aside-column"></aside> */}
            </div>
          </div>
        </div>
      </section>
    </Layout>
  );
};

export default BlogPage;
export const query = graphql`
  query BlogPageQuery {
    blog: allWpPost(limit: 3, filter: { categories: { nodes: { elemMatch: { id: { eq: "dGVybToyODE=" } } } } }) {
      nodes {
        id
        title
        date
        excerpt
        uri
        featuredImage {
          node {
            localFile {
              childImageSharp {
                gatsbyImageData(layout: FULL_WIDTH)
              }
            }
          }
        }
      }
    }
  }
`;
